struct Info {
	Info() :mn(INF) {};
	Info(int mn) :mn(mn) {};

	// 要维护的值
	int mn;
	void apply(const Info& v) {
		// 如何单点修改
		mn = v.mn;
	}
};
Info operator+(const Info& a, const Info& b) {
	Info c;
	c.mn = min(a.mn, b.mn);
	return c;
}
void solve(int CASE)
{
	int n; cin >> n;
	var a = vector<Info>(n + 1);
	var pos = vector<queue<int>>(n + 1);
	fa(i, 1, n) {
		int x; cin >> x;
		a[i] = x;
		pos[x].push(i);
	}
	var b = vector<int>(n + 1);
	fa(i, 1, n)cin >> b[i];
	var seg = SegmentTree<Info>(a);
	fa(i, 1, n) {
		int mn = seg.query(1, pos[b[i]].front()).mn;
		if (mn != b[i]) {
			cout << "NO" << endl;
			return;
		}
		seg.modify(pos[b[i]].front(), INF);
		pos[b[i]].pop();
	}
	cout << "YES" << endl;
	return;
}
